INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000001', E'카드 단말기 뭐 쓰세요?', E'루비아뜰리에입니다. 토스, 페이코, KIS 비교 중인데 수수료랑 사용감 어떤가요?', '자유게시판', 'seller', E'최다인', false, NULL, 54, true, NOW() - interval '51 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000002', E'리넨 에코백 재료 어디서 구매하시나요?', E'온라인으로만 사다가 오프라인 도매상도 가보고 싶은데 추천 부탁드려요. 서울 기준이면 더 좋아요!', '자유게시판', 'seller', E'박지윤', false, NULL, 53, true, NOW() - interval '19 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000002', E'카드 단말기 뭐 쓰세요?', E'엘르코지입니다. 토스, 페이코, KIS 비교 중인데 수수료랑 사용감 어떤가요?', '자유게시판', 'seller', E'박지윤', false, NULL, 12, true, NOW() - interval '23 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000003', E'브랜드 네이밍 고민 중이에요', E'지금 오월레몬로 활동 중인데 좀 더 컨셉이 명확한 이름으로 바꿀까 고민입니다. 다들 어떻게 정하셨나요?', '자유게시판', 'seller', E'한선우', false, NULL, 23, true, NOW() - interval '29 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000004', E'포장재 단가 비교해봤어요', E'실버 미니멀 주얼리 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'신윤서', false, NULL, 33, true, NOW() - interval '1 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000004', E'비슷한 품목 옆 부스 스트레스', E'실버 미니멀 주얼리 셀러인데 늘 비슷한 카테고리 옆에 배치되네요. 가격 경쟁 너무 힘들어요.', '익명', 'seller', NULL, true, E'익명263', 57, true, NOW() - interval '16 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000005', E'유리 공예 컵 셀러분들 디피 어떻게 하세요?', E'햇살소소이라는 작은 브랜드 운영 중이에요. 빈티지 분위기로 디피하려는데 팁 있으면 공유해주세요!', '자유게시판', 'seller', E'정은채', false, NULL, 62, true, NOW() - interval '4 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000006', E'인스타 운영 팁 공유해요', E'뜨개 모자·머플러 작가입니다. 인스타 1년 운영하면서 느낀 점 정리했어요. 1) 같은 시간 업로드 2) 해시태그 30개 풀로 3) 릴스 활용...', '자유게시판', 'seller', E'박승현', false, NULL, 72, true, NOW() - interval '8 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000007', E'포장재 단가 비교해봤어요', E'핸드드로잉 일러스트 굿즈 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'홍하윤', false, NULL, 8, true, NOW() - interval '54 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000007', E'인스타 운영 팁 공유해요', E'핸드드로잉 일러스트 굿즈 작가입니다. 인스타 1년 운영하면서 느낀 점 정리했어요. 1) 같은 시간 업로드 2) 해시태그 30개 풀로 3) 릴스 활용...', '자유게시판', 'seller', E'홍하윤', false, NULL, 47, true, NOW() - interval '37 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000008', E'카드 단말기 뭐 쓰세요?', E'미니리리입니다. 토스, 페이코, KIS 비교 중인데 수수료랑 사용감 어떤가요?', '자유게시판', 'seller', E'황수아', false, NULL, 51, true, NOW() - interval '25 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000008', E'포장재 단가 비교해봤어요', E'핸드메이드 향초 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'황수아', false, NULL, 2, true, NOW() - interval '3 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000009', E'[현장] 잠실 마켓 분위기 좋아요', E'라일락스튜디오 부스 운영 중! 사람 많고 분위기 최고예요. 비즈 팔찌·반지 인기 폭발!', '실시간 행사 현황', 'seller', E'류예은', false, NULL, 57, true, NOW() - interval '26 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000009', E'플리마켓 첫 참가 후기', E'저는 비즈 팔찌·반지 만드는 라일락스튜디오예요. 아이 키우면서 시작한 작은 브랜드예요. 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'류예은', false, NULL, 67, true, NOW() - interval '54 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000010', E'포장재 단가 비교해봤어요', E'도자기 컵·그릇 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'강지은', false, NULL, 38, true, NOW() - interval '14 days');
