INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e2000000-0000-0000-0000-000000000099', E'여름 야외 행사 생존 키트', E'오감대박 운영자가 추천하는 여름 필수템: 미니 선풍기, 얼음 텀블러, 쿨타올, 모기 스프레이, 양산. 체력 관리가 진짜 중요해요.', '자유게시판', 'foodtruck', E'최정훈', false, NULL, 54, true, NOW() - interval '45 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e2000000-0000-0000-0000-000000000099', E'[양도] 다음 주 트럭존 자리', E'오감대박(아이스크림) 다음 주 월드컵공원 푸드트럭존 자리 양도합니다. 일정 겹쳐서요. 참가비 그대로.', '행사 양도/양수', 'foodtruck', E'최정훈', false, NULL, 38, true, NOW() - interval '13 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e2000000-0000-0000-0000-000000000100', E'푸드트럭 창업 비용 현실', E'마망오븐 운영자입니다. 직장 그만두고 시작한 인생 2막입니다. 창업할 때 트럭 2500만, 개조 800만, 장비 500만 들었어요. 월 순수익 150~250만 정도.', '자유게시판', 'foodtruck', E'강유나', false, NULL, 8, true, NOW() - interval '57 days');
